import { createSlice, createEntityAdapter, createSelector } from '@reduxjs/toolkit';

const notificationAdapter = createEntityAdapter({
    selectId: (notification) => notification._id,
    sortComparer: (a, b) => b.createdAt.localeCompare(a.createdAt),
});

const initialState = notificationAdapter.getInitialState({
    Ids: [],
    isFetching: false,
    error: false
})

export const notificationSlice = createSlice({
    name: "notification",
    initialState: {
        notifications: [],
        isFetching: false,
        error: false,
    },
    reducers: {
        // GET ALL
        getNotificationStart: (state) => {
            state.isFetching = true;
            state.error = false;
        },
        getNotificationSuccess: (state, action) => {
            state.isFetching = false;
            state.notifications = action.payload.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
        },
        getNotificationFailure: (state) => {
            state.isFetching = false;
            state.error = true;
        },
        notificationToggleReadStart: (state) => {
            state.isFetching = true;
            state.error = false;
        },
        notificationToggleReadSuccess: (state, action) => {
            state.isFetching = false;
            const { id } = action.payload;
            const index = state.notifications.findIndex((notification) => notification._id === id);
            if (index !== -1) {
                state.notifications[index].read = !state.notifications[index].read
            }
        },
        notificationToggleReadFailure: (state) => {
            state.isFetching = false;
            state.error = true;
        },
        notificationReadStart: (state) => {
            state.isFetching = true;
            state.error = false;
        },
        notificationReadSuccess: (state, action) => {
            state.isFetching = false;
            const { id } = action.payload;
            const index = state.notifications.findIndex((notification) => notification._id === id);
            if (index !== -1) {
                state.notifications[index].read = true;
            }
        },
        notificationReadFailure: (state) => {
            state.isFetching = false;
            state.error = true;
        },
        allNotificationsReadStart: (state) => {
            state.isFetching = true;
            state.error = false;
        },
        allNotificationsReadSuccess: (state) => {
            state.notifications.forEach(notification => {
                notification.read = true
            })
        },
        allNotificationsReadFailure: (state) => {
            state.isFetching = false;
            state.error = true;            
        }
    },
});

export const { 
    getNotificationStart,
    getNotificationSuccess,
    getNotificationFailure,
    notificationToggleReadStart,
    notificationToggleReadSuccess,
    notificationToggleReadFailure,
    notificationReadStart,
    notificationReadSuccess,
    notificationReadFailure,
    allNotificationsReadStart,
    allNotificationsReadSuccess,
    allNotificationsReadFailure
} = notificationSlice.actions;

export default notificationSlice.reducer;

export const { selectAll: getAllNotifications } = notificationAdapter.getSelectors(state => state.notifications);

export const selectAllNotifications = state => state.notification.notifications;

export const selectNotificationsById = (state, notificationId) =>
    state.notification.notifications.find(notification => notification._id === notificationId);

export const selectNotificationsByUser = createSelector(
    [selectAllNotifications, (state, userId) => userId],
    (notifications, userId) => notifications.filter(notification => notification.userId === userId)
);
